<?php
require_once __DIR__.'/functions.php';require_admin();if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}verify_csrf();$id=filter_input(INPUT_POST,'post_id',FILTER_VALIDATE_INT);$action=(string)($_POST['action']??'');$stmt=db()->prepare("SELECT imagen FROM posts WHERE id=? AND post_type='community'");$stmt->execute([$id]);$post=$stmt->fetch();if(!$post){http_response_code(404);exit('Publicación no encontrada.');}if($action==='approve'){db()->prepare("UPDATE posts SET status='published' WHERE id=?")->execute([$id]);flash('Publicación aprobada.');}elseif($action==='reject'){db()->prepare("UPDATE posts SET status='rejected' WHERE id=?")->execute([$id]);flash('Publicación rechazada.');}elseif($action==='delete'){db()->prepare('DELETE FROM posts WHERE id=?')->execute([$id]);delete_image($post['imagen']);flash('Publicación eliminada.');}else{http_response_code(400);exit('Acción inválida.');}redirect('/community-moderation.php');
